import math
from typing import List, Tuple, Dict

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two real numbers to six significant digits.

    Returns "LT" if a < b, "EQ" if a == b, "GT" if a > b
    under six-significant-digit comparison.
    """
    def round_sig(x: float, sig: int = 6) -> float:
        if x == 0.0:
            return 0.0
        return round(x, sig - 1 - int(math.floor(math.log10(abs(x)))))

    ar = round_sig(a)
    br = round_sig(b)
    if ar < br:
        return "LT"
    if ar > br:
        return "GT"
    return "EQ"


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, float],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    def points_equal(i: int, j: int) -> bool:
        return realcompare(x[i], x[j]) == "EQ" and realcompare(y[i], y[j]) == "EQ"

    def dist(i: int, j: int) -> float:
        return math.hypot(x[j] - x[i], y[j] - y[i])

    def triangle_area(i: int, j: int, k: int) -> float:
        return 0.5 * abs((x[j] - x[i]) * (y[k] - y[i]) - (x[k] - x[i]) * (y[j] - y[i]))

    def angle_at_vertex(i: int, j: int, k: int):
        # angle at point j using points i-j-k
        if points_equal(i, j) or points_equal(k, j):
            return None
        v1x = x[i] - x[j]
        v1y = y[i] - y[j]
        v2x = x[k] - x[j]
        v2y = y[k] - y[j]
        len1 = math.hypot(v1x, v1y)
        len2 = math.hypot(v2x, v2y)
        if realcompare(len1, 0.0) == "EQ" or realcompare(len2, 0.0) == "EQ":
            return None
        dot = v1x * v2x + v1y * v2y
        cosang = dot / (len1 * len2)
        if cosang > 1.0:
            cosang = 1.0
        elif cosang < -1.0:
            cosang = -1.0
        return math.acos(cosang)

    def min_enclosing_radius(i: int, j: int, k: int) -> float:
        # minimal circle radius for 3 points
        d_ij = dist(i, j)
        d_jk = dist(j, k)
        d_ik = dist(i, k)
        d_vals = [d_ij, d_jk, d_ik]
        dmax = d_vals[0]
        dmax_idx = 0
        for idx in range(1, 3):
            if realcompare(d_vals[idx], dmax) == "GT":
                dmax = d_vals[idx]
                dmax_idx = idx
        area = triangle_area(i, j, k)
        if realcompare(area, 0.0) == "EQ":
            return dmax / 2.0
        # identify longest side for obtuse/right check
        if dmax_idx == 0:
            a2 = d_jk * d_jk
            b2 = d_ik * d_ik
            c2 = d_ij * d_ij
        elif dmax_idx == 1:
            a2 = d_ij * d_ij
            b2 = d_ik * d_ik
            c2 = d_jk * d_jk
        else:
            a2 = d_ij * d_ij
            b2 = d_jk * d_jk
            c2 = d_ik * d_ik
        if realcompare(c2, a2 + b2) in ("GT", "EQ"):
            return dmax / 2.0
        # acute: circumradius
        return (d_ij * d_jk * d_ik) / (4.0 * area)

    def distance_point_to_line(i: int, j: int, k: int) -> float:
        # distance from point k to line through i-j
        x1 = x[i]
        y1 = y[i]
        x2 = x[j]
        y2 = y[j]
        x0 = x[k]
        y0 = y[k]
        num = abs((y2 - y1) * x0 - (x2 - x1) * y0 + x2 * y1 - y2 * x1)
        den = math.hypot(y2 - y1, x2 - x1)
        if realcompare(den, 0.0) == "EQ":
            return dist(i, k)
        return num / den

    def quadrant(i: int) -> int:
        if realcompare(x[i], 0.0) in ("GT", "EQ") and realcompare(y[i], 0.0) in ("GT", "EQ"):
            return 1
        if realcompare(x[i], 0.0) in ("LT", "EQ") and realcompare(y[i], 0.0) in ("GT", "EQ"):
            return 2
        if realcompare(x[i], 0.0) in ("LT", "EQ") and realcompare(y[i], 0.0) in ("LT", "EQ"):
            return 3
        return 4

    cmv = [False] * 15

    # LIC 1
    for i in range(numpoints - 1):
        if realcompare(dist(i, i + 1), parameters["LENGTH1"]) == "GT":
            cmv[0] = True
            break

    # LIC 2
    for i in range(numpoints - 2):
        r = min_enclosing_radius(i, i + 1, i + 2)
        if realcompare(r, parameters["RADIUS1"]) == "GT":
            cmv[1] = True
            break

    # LIC 3
    for i in range(numpoints - 2):
        ang = angle_at_vertex(i, i + 1, i + 2)
        if ang is None:
            continue
        if realcompare(ang, PI - parameters["EPSILON"]) == "LT" or realcompare(
            ang, PI + parameters["EPSILON"]
        ) == "GT":
            cmv[2] = True
            break

    # LIC 4
    for i in range(numpoints - 2):
        area = triangle_area(i, i + 1, i + 2)
        if realcompare(area, parameters["AREA1"]) == "GT":
            cmv[3] = True
            break

    # LIC 5
    q_pts = parameters["Q_PTS"]
    quads = parameters["QUADS"]
    for start in range(numpoints - q_pts + 1):
        qs = set()
        for i in range(start, start + q_pts):
            qs.add(quadrant(i))
        if len(qs) > quads:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        if realcompare(x[i + 1] - x[i], 0.0) == "LT":
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3:
        n_pts = parameters["N_PTS"]
        dist_limit = parameters["DIST"]
        for start in range(numpoints - n_pts + 1):
            first = start
            last = start + n_pts - 1
            if points_equal(first, last):
                for k in range(start + 1, last):
                    if realcompare(dist(first, k), dist_limit) == "GT":
                        cmv[6] = True
                        break
            else:
                for k in range(start + 1, last):
                    d = distance_point_to_line(first, last, k)
                    if realcompare(d, dist_limit) == "GT":
                        cmv[6] = True
                        break
            if cmv[6]:
                break

    # LIC 8
    if numpoints >= 3:
        k_pts = parameters["K_PTS"]
        for i in range(numpoints - k_pts - 1):
            j = i + k_pts + 1
            if realcompare(dist(i, j), parameters["LENGTH1"]) == "GT":
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        a_pts = parameters["A_PTS"]
        b_pts = parameters["B_PTS"]
        for i in range(numpoints - (a_pts + b_pts + 2)):
            j = i + a_pts + 1
            k = j + b_pts + 1
            r = min_enclosing_radius(i, j, k)
            if realcompare(r, parameters["RADIUS1"]) == "GT":
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        c_pts = parameters["C_PTS"]
        d_pts = parameters["D_PTS"]
        for i in range(numpoints - (c_pts + d_pts + 2)):
            j = i + c_pts + 1
            k = j + d_pts + 1
            ang = angle_at_vertex(i, j, k)
            if ang is None:
                continue
            if realcompare(ang, PI - parameters["EPSILON"]) == "LT" or realcompare(
                ang, PI + parameters["EPSILON"]
            ) == "GT":
                cmv[9] = True
                break

    # LIC 11
    if numpoints >= 5:
        e_pts = parameters["E_PTS"]
        f_pts = parameters["F_PTS"]
        for i in range(numpoints - (e_pts + f_pts + 2)):
            j = i + e_pts + 1
            k = j + f_pts + 1
            area = triangle_area(i, j, k)
            if realcompare(area, parameters["AREA1"]) == "GT":
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        g_pts = parameters["G_PTS"]
        for i in range(numpoints - g_pts - 1):
            j = i + g_pts + 1
            if realcompare(x[j] - x[i], 0.0) == "LT":
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        k_pts = parameters["K_PTS"]
        length1 = parameters["LENGTH1"]
        length2 = parameters["LENGTH2"]
        gt_length1 = False
        lt_length2 = False
        for i in range(numpoints - k_pts - 1):
            j = i + k_pts + 1
            d = dist(i, j)
            if realcompare(d, length1) == "GT":
                gt_length1 = True
            if realcompare(d, length2) == "LT":
                lt_length2 = True
            if gt_length1 and lt_length2:
                break
        cmv[12] = gt_length1 and lt_length2

    # LIC 14
    if numpoints >= 5:
        a_pts = parameters["A_PTS"]
        b_pts = parameters["B_PTS"]
        r1 = parameters["RADIUS1"]
        r2 = parameters["RADIUS2"]
        gt_r1 = False
        le_r2 = False
        for i in range(numpoints - (a_pts + b_pts + 2)):
            j = i + a_pts + 1
            k = j + b_pts + 1
            r = min_enclosing_radius(i, j, k)
            if realcompare(r, r1) == "GT":
                gt_r1 = True
            if realcompare(r, r2) in ("LT", "EQ"):
                le_r2 = True
            if gt_r1 and le_r2:
                break
        cmv[13] = gt_r1 and le_r2

    # LIC 15
    if numpoints >= 5:
        e_pts = parameters["E_PTS"]
        f_pts = parameters["F_PTS"]
        area1 = parameters["AREA1"]
        area2 = parameters["AREA2"]
        gt_area1 = False
        lt_area2 = False
        for i in range(numpoints - (e_pts + f_pts + 2)):
            j = i + e_pts + 1
            k = j + f_pts + 1
            area = triangle_area(i, j, k)
            if realcompare(area, area1) == "GT":
                gt_area1 = True
            if realcompare(area, area2) == "LT":
                lt_area2 = True
            if gt_area1 and lt_area2:
                break
        cmv[14] = gt_area1 and lt_area2

    # PUM
    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = pum_diag[i]
    for i in range(15):
        for j in range(15):
            if i == j:
                continue
            connector = lcm[i][j]
            if connector == "NOTUSED":
                pum[i][j] = True
            elif connector == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif connector == "ORR":
                pum[i][j] = cmv[i] or cmv[j]
            else:
                pum[i][j] = False

    # FUV
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            row_all = True
            for j in range(15):
                if not pum[i][j]:
                    row_all = False
                    break
            fuv[i] = row_all

    launch = True
    for v in fuv:
        if not v:
            launch = False
            break

    return cmv, pum, fuv, launch
